const { Knock } = require("@knocklabs/mgmt");

async function main() {
  const runId = process.env.ZEALT_RUN_ID;
  const knock = new Knock(process.env.KNOCK_SERVICE_TOKEN);
  const workflowKey = `popover-demo-${runId}`;

  try {
    console.log("Upserting workflow...");
    await knock.workflows.upsert(workflowKey, {
      name: `Popover Demo ${runId}`,
      steps: [
        {
          ref: "in-app-step",
          type: "channel",
          channel_key: "in-app",
          settings: {},
          template: {
            html_body: "{{ data.body }}",
            markdown_body: "{{ data.body }}",
            text_body: "{{ data.body }}"
          }
        }
      ]
    });
    console.log("Workflow upserted.");

    console.log("Activating workflow...");
    await knock.workflows.activate(workflowKey, {
      environment: "development"
    });
    console.log("Workflow activated.");
  } catch (error) {
    console.error("Error:", error.response ? error.response.data : error.message);
  }
}

main();

